//! Wasm entry: two-view SfM relative-pose solve.
//!
//! `cfg`-gated `wasm32` only. The `depth-onnx`/`ort` features are OFF for this
//! target by construction (the `depth_onnx` module is `cfg`-excluded on wasm32),
//! so this path is sovereign and weight-free.

use wasm_bindgen::prelude::*;

use crate::sfm_two_view::{solve_two_view, SfmConfig, SfmOutcome};

/// Result of [`sfm_solve`]: a JSON document describing either the recovered pose
/// or an honest null. Shape:
///
/// ```json
/// // pose:
/// { "ok": true, "r": [[..],[..],[..]], "t": [x,y,z],
///   "intrinsics": {"fx":..,"fy":..,"cx":..,"cy":..},
///   "inliers": 73, "matches": 91, "medianParallaxDeg": 6.2, "confidence": 0.71 }
/// // honest null:
/// { "ok": false, "reason": "...", "confidence": 0.0 }
/// ```
#[wasm_bindgen]
pub struct WasmSfmResult {
    #[wasm_bindgen(skip)]
    json: String,
    is_pose: bool,
    confidence: f64,
}

#[wasm_bindgen]
impl WasmSfmResult {
    #[wasm_bindgen(getter)]
    pub fn json(&self) -> String {
        self.json.clone()
    }
    /// `true` when a trustworthy pose was recovered; `false` = honest null
    /// (caller should fall back, e.g. to the turntable carve).
    #[wasm_bindgen(getter, js_name = isPose)]
    pub fn is_pose(&self) -> bool {
        self.is_pose
    }
    #[wasm_bindgen(getter)]
    pub fn confidence(&self) -> f64 {
        self.confidence
    }
}

/// Solve the relative pose of camera2 vs camera1 from two **grayscale** frames
/// (`u8`, row-major, length `width*height` each). Returns a [`WasmSfmResult`]
/// with a JSON pose or an honest null. Never fabricates a pose.
///
/// `fast_threshold` / `min_parallax_deg` of 0 select the [`SfmConfig::default`]
/// values (handy for the JS caller that doesn't want to tune).
#[wasm_bindgen(js_name = sfmSolve)]
pub fn sfm_solve(
    gray1: &[u8],
    gray2: &[u8],
    width: u32,
    height: u32,
    fast_threshold: u8,
    min_parallax_deg: f32,
) -> Result<WasmSfmResult, JsError> {
    let mut cfg = SfmConfig::default();
    if fast_threshold > 0 {
        cfg.fast_threshold = fast_threshold;
    }
    if min_parallax_deg > 0.0 {
        cfg.min_parallax_deg = min_parallax_deg as f64;
    }
    let outcome = solve_two_view(gray1, gray2, width as usize, height as usize, &cfg);
    let (is_pose, confidence) = match &outcome {
        SfmOutcome::Pose(p) => (true, p.confidence),
        SfmOutcome::Null { confidence, .. } => (false, *confidence),
    };
    let json = outcome_to_json(&outcome);
    Ok(WasmSfmResult { json, is_pose, confidence })
}

fn outcome_to_json(o: &SfmOutcome) -> String {
    match o {
        SfmOutcome::Pose(p) => {
            let r = format!(
                "[[{},{},{}],[{},{},{}],[{},{},{}]]",
                p.r[0][0], p.r[0][1], p.r[0][2],
                p.r[1][0], p.r[1][1], p.r[1][2],
                p.r[2][0], p.r[2][1], p.r[2][2],
            );
            format!(
                "{{\"ok\":true,\"r\":{},\"t\":[{},{},{}],\"intrinsics\":{{\"fx\":{},\"fy\":{},\"cx\":{},\"cy\":{}}},\"inliers\":{},\"matches\":{},\"medianParallaxDeg\":{},\"confidence\":{}}}",
                r, p.t[0], p.t[1], p.t[2],
                p.intrinsics.fx, p.intrinsics.fy, p.intrinsics.cx, p.intrinsics.cy,
                p.inliers, p.matches, p.median_parallax_deg, p.confidence,
            )
        }
        SfmOutcome::Null { reason, confidence } => {
            let safe = reason.replace('\\', "\\\\").replace('"', "\\\"");
            format!(
                "{{\"ok\":false,\"reason\":\"{}\",\"confidence\":{}}}",
                safe, confidence
            )
        }
    }
}
